<?php
use Livewire\Component;
new class extends Component { public \App\Models\Submission $submission; public function mount(\App\Models\Submission $submission): void { $this->submission = $submission->load('quiz'); } public function interpretation(): string { foreach (($this->submission->quiz->interpretation_ranges ?? []) as $range) { if ($this->submission->score >= $range['min'] && $this->submission->score <= $range['max']) return $range['label']; } return $this->submission->quiz->type === 'quiz' ? ($this->submission->percentage >= $this->submission->quiz->passing_score ? 'Lulus' : 'Belum lulus') : 'Hasil refleksi Anda'; } }; ?>
<section class="result-panel"><p class="eyebrow">ASSESSMENT COMPLETE</p><h1>Terima kasih, {{ $submission->participant_name }}.</h1><div class="score-ring"><strong>{{ $submission->quiz->type === 'assessment' ? $submission->score : $submission->percentage.'%' }}</strong><span>{{ $submission->quiz->type === 'assessment' ? 'skor refleksi' : 'skor' }}</span></div><h2>{{ $this->interpretation() }}</h2><p>Gunakan hasil ini sebagai titik awal untuk memahami kondisi Anda. Untuk dukungan profesional, hubungi psikolog atau layanan kesehatan mental tepercaya.</p><a class="button" href="/">Kembali ke beranda</a></section>
